args.cypher:
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE EXISTS {
  MATCH (aas)-[:HAS_DESCRIPTION]->(d:LangString) WHERE toLower(d.text) CONTAINS 'hall 4'
}
   OR EXISTS {
  MATCH (aas)-[:HAS_DISPLAY_NAME]->(dn:LangString) WHERE toLower(dn.text) CONTAINS 'hall 4'
}
RETURN aas.idShort, aas.id, aas.category

MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
      -[:HAS_SEMANTIC_ID]->(sc:SemanticConcept {id: 'https://admin-shell.io/Submodel/Assets/Location/0'})
WHERE EXISTS {
  MATCH (sm)-[:HAS_ELEMENT*]->(p:Property)-[:HAS_VALUE]->(ls:LangString {language: 'en', text: 'Hall 4'})
}
   OR EXISTS {
  MATCH (sm)-[:HAS_ELEMENT*]->(p:Property)-[:HAS_VALUE]->(ls:LangString {text: 'Hall 4'})
}
RETURN aas.id AS aas_id, aas.idShort AS aas_idShort, sm.idShort AS sm_idShort
LIMIT 10

MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(asset:Asset)
WHERE asset.globalAssetId = $serialNumber
   OR EXISTS {
     MATCH (aas)-[:HAS_SUBMODEL]->(sm:Submodel)-[:HAS_ELEMENT*]->(prop:Property)
     WHERE prop.idShort = 'serialNumber' AND prop.value = $serialNumber
   }
   OR EXISTS {
     MATCH (aas)-[:HAS_SUBMODEL]->(sm:Submodel)-[:HAS_ELEMENT*]->(prop:Property)
     WHERE prop.idShort = 'SerialNumber' AND prop.value = $serialNumber
   }
RETURN aas.id AS aas_id, aas.idShort AS aas_idShort, asset.globalAssetId AS serial, asset.assetKind
